-- 0034_backfill_repository_settings.up.sql
--
-- One-time backfill: every repository that existed before the
-- per-repository settings feature (migration 0033) gets a full
-- settings seed so it keeps working AND becomes configurable from
-- the repository-settings UI.
--
-- Providers: every known provider id is seeded enabled=TRUE. The
-- known catalog is hardcoded here because a SQL migration cannot
-- ask the live Go provider registry. Orphans (ids not live in a
-- given deployment) are silently ignored at enforcement time, so
-- seeding the full catalog is safe. New providers added after this
-- migration do NOT auto-backfill into existing repos; an admin adds
-- them via the UI (or the operator runs a one-off query).
--
-- Contexts: every label from the embedded dbpedia_l3.json snapshot
-- is seeded with is_custom=FALSE, description=''. The label list is
-- inlined as a JSON text constant (generated from the committed
-- dbpedia_l3.json so the backfill is self-contained and in sync
-- with the embedded snapshot at the time of migration). The label
-- set is a snapshot for legacy repos; new repos seeded at creation
-- also use dbpedia_l3.json, so a later `just dbpedia-pull` that
-- updates the file changes what new repos get but does NOT re-run
-- this backfill.

INSERT INTO okt_system.repository_provider_settings (repository_id, provider_kind, provider_id, enabled)
SELECT r.id, v.kind, v.provider_id, TRUE
FROM okt_system.repositories r
CROSS JOIN (VALUES
    ('search', 'serper'),
    ('search', 'openalex'),
    ('resolution', 'fetch'),
    ('resolution', 'unpaywall'),
    ('resolution', 'tls'),
    ('resolution', 'flaresolverr')
) AS v(kind, provider_id)
WHERE NOT EXISTS (
    SELECT 1 FROM okt_system.repository_provider_settings s
     WHERE s.repository_id = r.id
       AND s.provider_kind = v.kind
       AND s.provider_id = v.provider_id
);

-- Contexts: inline the dbpedia L3 label array. Using a JSON text
-- constant + jsonb_array_elements_text so the migration is a
-- single self-contained statement (no COPY, no external file).
